import React, { useState, useEffect, useRef } from 'react';
import { useParams, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useSocket } from '../context/SocketContext';
import axios from 'axios';
import BingoBoard from '../components/BingoBoard';
import './GameRoom.css';

function GameRoom() {
  const { roomId } = useParams();
  const location = useLocation();
  const navigate = useNavigate();
  const { user, updateBalance } = useAuth();
  const { socket, isConnected, on, emit } = useSocket();
  
  const [game, setGame] = useState(null);
  const [cartelas, setCartelas] = useState(location.state?.cartelas || []);
  const [calledNumbers, setCalledNumbers] = useState([]);
  const [countdown, setCountdown] = useState(null);
  const [gameActive, setGameActive] = useState(false);
  const [winner, setWinner] = useState(null);
  const [lastCalled, setLastCalled] = useState(null);
  const [players, setPlayers] = useState([]);
  const [pool, setPool] = useState(0);
  const [loading, setLoading] = useState(true);
  const [showWinnerModal, setShowWinnerModal] = useState(false);
const [winnerInfo, setWinnerInfo] = useState(null);
  const audioRef = useRef(null);
  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

  // Helper function to safely parse cartela data
  const parseCartelaData = (cartelaData) => {
    if (!cartelaData) return null;
    if (typeof cartelaData === 'string') {
      try {
        return JSON.parse(cartelaData);
      } catch (e) {
        console.error('Error parsing cartela data:', e);
        return null;
      }
    }
    return cartelaData;
  };

  // Bingo letters mapping
  const getLetter = (number) => {
    if (number <= 15) return 'B';
    if (number <= 30) return 'I';
    if (number <= 45) return 'N';
    if (number <= 60) return 'G';
    return 'O';
  };

  // Check if number is marked on a cartela
  const isNumberMarked = (cartela, number) => {
    const markedNumbers = cartela.marked_numbers || [];
    return markedNumbers.includes(number);
  };

  // Toggle auto/manual mode
  const toggleMode = (cartelaId, currentMode) => {
    if (emit) {
      emit('toggle_mode', {
        cartelaId: cartelaId,
        isAutoMode: !currentMode
      });
      
      setCartelas(prev => prev.map(c => 
        c.id === cartelaId ? { ...c, is_auto_mode: !currentMode } : c
      ));
    }
  };

  // Manually mark a number
  const markNumber = (cartelaId, number) => {
    if (!gameActive) {
      alert('Game is not active!');
      return;
    }
    
    if (emit) {
      emit('mark_number', {
        gameId: game?.id,
        cartelaId: cartelaId,
        number: number
      });
    }
  };

  // Call BINGO
  const callBingo = (cartelaId) => {
    if (!gameActive) {
      alert('Game is not active!');
      return;
    }
    
    if (window.confirm('Are you sure you want to call BINGO?')) {
      if (emit) {
        emit('call_bingo', {
          gameId: game?.id,
          cartelaId: cartelaId
        });
      }
    }
  };

  // Leave room
  const leaveRoom = async () => {
    if (gameActive) {
      alert('Cannot leave during active game!');
      return;
    }
    
    if (window.confirm('Are you sure you want to leave this room?')) {
      try {
        const token = localStorage.getItem('token');
        await axios.post(`${API_URL}/game/rooms/${roomId}/leave`, {}, {
          headers: { Authorization: `Bearer ${token}` }
        });
        navigate('/');
      } catch (error) {
        console.error('Leave room error:', error);
        alert('Failed to leave room');
      }
    }
  };

  // Fetch game state
  const fetchGameState = async () => {
    if (!location.state?.gameId) return;
    
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`${API_URL}/game/games/${location.state.gameId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      console.log('Game state:', response.data);
      setGame(response.data.game);
      setCartelas(response.data.cartelas || []);
      setPlayers(response.data.players || []);
      setPool(response.data.game.total_pool || 0);
      
      if (response.data.game.status === 'active') {
        setGameActive(true);
      }
    } catch (error) {
      console.error('Fetch game error:', error);
      navigate('/');
    }
  };

  // Refresh cartelas periodically
  const refreshCartelas = async () => {
    if (!game?.id) return;
    
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`${API_URL}/game/games/${game.id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCartelas(response.data.cartelas || []);
      setPlayers(response.data.players || []);
      setPool(response.data.game.total_pool || 0);
    } catch (error) {
      console.error('Refresh error:', error);
    }
  };

  useEffect(() => {
    if (location.state?.gameId) {
      fetchGameState();
    } else {
      navigate('/');
    }
  }, [location.state]);

  // Socket event listeners
  useEffect(() => {
    if (!socket) return;

    // Join game room
    if (game?.id) {
      emit('join_game', { gameId: game.id });
    }

    // Countdown listener
    const unsubscribeCountdown = on('countdown', (data) => {
      console.log('Countdown:', data);
      setCountdown(data.seconds);
    });

    // Waiting for players
    const unsubscribeWaiting = on('waiting_for_players', (data) => {
      console.log('Waiting for players:', data);
      setGameActive(false);
      setCountdown(null);
    });

    // Game state
    const unsubscribeGameState = on('game_state', (data) => {
      console.log('Game state received:', data);
      setCalledNumbers(data.calledNumbers || []);
      setGameActive(true);
      setCountdown(null);
    });

    // Number called
    const unsubscribeNumberCalled = on('number_called', (data) => {
      console.log('Number called:', data);
      setLastCalled({ number: data.number, letter: data.letter });
      setCalledNumbers(data.calledNumbers || []);
      setTimeout(() => refreshCartelas(), 100);
    });

    // Auto marked
    const unsubscribeAutoMarked = on('auto_marked', (data) => {
      console.log('Auto marked:', data);
      setCartelas(prev => prev.map(c => 
        c.id === data.cartelaId 
          ? { ...c, marked_numbers: [...(c.marked_numbers || []), data.number] }
          : c
      ));
    });

    // Number marked (manual)
    const unsubscribeNumberMarked = on('number_marked', (data) => {
      console.log('Number marked:', data);
      setCartelas(prev => prev.map(c => 
        c.id === data.cartelaId 
          ? { ...c, marked_numbers: [...(c.marked_numbers || []), data.number] }
          : c
      ));
    });

    // Game ended
    const unsubscribeGameEnded = on('game_ended', (data) => {
      console.log('Game ended:', data);
      setGameActive(false);
      setWinner(data.winners);
      
      if (data.winners && data.winners.length > 0) {
        const isWinner = data.winners.some(w => w.userId === user?.id);
        if (isWinner) {
          alert(`🎉 CONGRATULATIONS! You won ${data.prizeAmount || 'some'} Birr! 🎉`);
          if (updateBalance && user) {
            updateBalance((user.wallet_balance || 0) + (data.prizeAmount || 0));
          }
        } else {
          alert(`Game ended! Winner won ${data.prizeAmount || 'some'} Birr`);
        }
      } else {
        alert('Game ended with no winner!');
      }
      
      setTimeout(() => {
        navigate('/');
      }, 5000);
    });

    // Invalid bingo
    const unsubscribeInvalidBingo = on('invalid_bingo', (data) => {
      alert('Invalid BINGO pattern! Check your numbers carefully.');
    });

    // Bonus awarded
    const unsubscribeBonusAwarded = on('bonus_awarded', (data) => {
      alert(`🎁 ${data.message}`);
      if (updateBalance && user) {
        updateBalance((user.wallet_balance || 0) + (data.amount || 0));
      }
    });

    // Refresh interval
    const refreshInterval = setInterval(refreshCartelas, 3000);

    return () => {
      unsubscribeCountdown();
      unsubscribeWaiting();
      unsubscribeGameState();
      unsubscribeNumberCalled();
      unsubscribeAutoMarked();
      unsubscribeNumberMarked();
      unsubscribeGameEnded();
      unsubscribeInvalidBingo();
      unsubscribeBonusAwarded();
      clearInterval(refreshInterval);
    };
  }, [socket, game, user]);

  useEffect(() => {
    setLoading(false);
  }, []);

  if (loading) {
    return (
      <div className="game-loading">
        <div className="loader"></div>
        <p>Loading game...</p>
      </div>
    );
  }

  return (
  <div className="game-room">
    <audio ref={audioRef} src="/sounds/bell.mp3" preload="auto" />
    
    {/* Header */}
    <header className="game-header">
      <div className="game-info">
        <h1>🎰 Room: {game?.room_name || roomId}</h1>
        <div className="game-stats">
          <div className="stat">💰 Pool: {pool} Birr</div>
          <div className="stat">👥 Players: {players.length}</div>
          <div className="stat">💵 Balance: {user?.wallet_balance || 0} Birr</div>
        </div>
      </div>
     {/* In the header section, update the exit button */}
<button 
  className="btn-leave" 
  onClick={leaveRoom} 
  style={{ display: gameActive ? 'none' : 'block' }}
>
  Exit Room
</button>
    </header>

    {/* Game Status */}
    <div className="game-status glass-card">
      {gameActive ? (
        <div className="status-active">
          <span className="pulse">🔴 GAME ACTIVE</span>
          <div className="last-called">
            {lastCalled && (
              <>
                Last Called: 
                <span className="called-number-big">
                  {lastCalled.letter}{lastCalled.number}
                </span>
              </>
            )}
          </div>
        </div>
      ) : countdown !== null ? (
        <div className="status-countdown">
          <span>⏰ Game starts in:</span>
          <span className="countdown-number">{countdown}s</span>
        </div>
      ) : (
        <div className="status-waiting">
          <span>⏳ Waiting for players...</span>
          <span>Need at least 2 players to start</span>
        </div>
      )}
    </div>

    {/* Two Column Layout */}
    <div className="game-main-layout">
      {/* Left Column - BINGO Board */}
      <div className="game-left-column">
        <BingoBoard calledNumbers={calledNumbers} />
        
        {/* Recent Numbers */}
        <div className="called-numbers glass-card">
          <h3>Recent Numbers</h3>
          <div className="numbers-grid">
            {calledNumbers.slice(-20).reverse().map((num, idx) => (
              <div key={idx} className="called-number-chip">
                {getLetter(num)}{num}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Right Column - Cartelas */}
      <div className="game-right-column">
        <div className="cartelas-container">
          {cartelas.map((cartela, idx) => {
            const cartelaData = parseCartelaData(cartela.cartela_data);
            if (!cartelaData) return null;
            
            const isAuto = cartela.is_auto_mode;
            
            return (
              <div key={cartela.id} className="cartela-card glass-card">
                <div className="cartela-header">
                  <h3>Cartela #{idx + 1} (Lucky #{cartela.lucky_number})</h3>
                  <div className="cartela-controls">
                    <button 
                      className={`mode-toggle ${isAuto ? 'auto' : 'manual'}`}
                      onClick={() => toggleMode(cartela.id, isAuto)}
                    >
                      {isAuto ? '🤖 Auto' : '✋ Manual'}
                    </button>
                    <button 
                      className="btn-bingo"
                      onClick={() => callBingo(cartela.id)}
                      disabled={!gameActive}
                    >
                      BINGO!
                    </button>
                  </div>
                </div>
                
                <div className="bingo-card">
                  <div className="bingo-header">
                    <div>B</div><div>I</div><div>N</div><div>G</div><div>O</div>
                  </div>
                  
                  {[0, 1, 2, 3, 4].map(row => (
                    <div key={row} className="bingo-row">
                      {[0, 1, 2, 3, 4].map(col => {
                        const number = cartelaData[col]?.[row];
                        const isFree = number === 'FREE';
                        const isMarked = isFree || isNumberMarked(cartela, number);
                        
                        return (
                          <div
                            key={`${col}-${row}`}
                            className={`bingo-cell ${isMarked ? 'marked' : ''} ${isFree ? 'free' : ''}`}
                            onClick={() => {
                              if (!gameActive) return;
                              if (isAuto) {
                                alert('Auto mode enabled! Numbers are marked automatically.');
                                return;
                              }
                              if (number !== 'FREE' && !isMarked) {
                                markNumber(cartela.id, number);
                              }
                            }}
                          >
                            {isFree ? '⭐' : number}
                          </div>
                        );
                      })}
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>

    {/* Winner Announcement */}
    {winner && winner.length > 0 && (
      <div className="winner-announcement glass-card">
        <div className="winner-content">
          <span className="winner-emoji">🏆</span>
          <h2>WINNER!</h2>
          {winner.map((w, idx) => (
            <p key={idx}>
              {w.userId === user?.id ? '🎉 YOU WON! 🎉' : `Player ${w.userId} won!`}
            </p>
          ))}
        </div>
      </div>
    )}
  </div>
);
}

export default GameRoom;
